const raw = $json.body ?? $json;
const payload = raw.data ?? raw;

const FIXED_CONFIG = {
  origin_name: 'Perpétuo Webinário',
  origin_id: 'bd1bd846-0c87-4acb-b221-d7f8d2089e68',
  tag_name: 'cj-ppt-webinar',
  lista_origem: 'cj-ppt-webinar',
  produto: 'VDE Carreiras Jurídicas Ciclo Prioritário',
  value: 2557
};

function normalizeKey(value) {
  return String(value || '')
    .trim()
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[?!:;,.()\[\]'"]/g, '')
    .replace(/[-_/]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function normalizeValue(value) {
  if (value === undefined || value === null) return '';
  return String(value).trim();
}

function digitsOnly(value) {
  return String(value || '').replace(/\D/g, '');
}

const containers = [payload, payload.fields || {}, payload.custom_fields || {}, payload.contact || {}];

function pickValue(aliases) {
  for (const alias of aliases) {
    const wanted = normalizeKey(alias);
    for (const container of containers) {
      for (const [k, v] of Object.entries(container || {})) {
        if (normalizeKey(k) === wanted) {
          const cleaned = normalizeValue(v);
          if (cleaned) return cleaned;
        }
      }
    }
  }
  return '';
}

const nome = pickValue(['nome', 'name', 'full_name', 'first_name']);
const email = pickValue(['email', 'e-mail', 'mail']);
const whatsappRaw = pickValue(['whatsapp', 'phone', 'telefone', 'celular']);
const carreiraPretendida = pickValue(['carreira_pretendida', 'carreira pretendida']);

const utmSource = pickValue(['utm_source', 'utm source']);
const utmMedium = pickValue(['utm_medium', 'utm medium']);
const utmCampaign = pickValue(['utm_campaign', 'utm campaign']);
const utmTerm = pickValue(['utm_term', 'utm term']);
const utmContent = pickValue(['utm_content', 'utm content']);

const whatsappDigits = digitsOnly(whatsappRaw);
const isValid = Boolean(email || whatsappDigits);

return [
  {
    json: {
      status: isValid ? 'bootstrap_ready' : 'validation_error',
      message: isValid
        ? 'Webhook Manychat recebido e normalizado com sucesso (modo bootstrap).'
        : 'Payload invalido: informe ao menos email ou whatsapp.',
      received_at: new Date().toISOString(),
      is_valid: isValid,
      endpoint: 'manychat-intake-test',
      fixed_config: FIXED_CONFIG,
      normalized_payload: {
        nome,
        email,
        whatsapp: whatsappRaw,
        whatsapp_digits: whatsappDigits,
        carreira_pretendida: carreiraPretendida,
        utm_source: utmSource,
        utm_medium: utmMedium,
        utm_campaign: utmCampaign,
        utm_term: utmTerm,
        utm_content: utmContent
      },
      raw_payload: payload
    }
  }
];
